import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { DepartmentService, TeamService, SkillService } from '../../core/services/api.services';
import { Department, Team, Skill } from '../../core/models';

@Component({ selector: 'app-register', templateUrl: './register.component.html' })
export class RegisterComponent implements OnInit {
  step = 1;
  form: any = {
    email: '', password: '', confirmPassword: '', firstName: '', lastName: '',
    role: 'EMPLOYEE', departmentId: null, teamId: null,
    skillIds: [], experienceYears: 0, maxCapacityHours: 40, bio: ''
  };
  departments: Department[] = [];
  teams: Team[] = [];
  skills: Skill[] = [];
  error = ''; loading = false;

  constructor(
    private auth: AuthService,
    private router: Router,
    private deptService: DepartmentService,
    private teamService: TeamService,
    private skillService: SkillService
  ) {}

  ngOnInit(): void {
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
    this.skillService.getAll().subscribe(r => { if (r.success) this.skills = r.data; });
  }

  onDeptChange(): void {
    this.form.teamId = null;
    if (this.form.departmentId) {
      this.teamService.getByDept(this.form.departmentId).subscribe(r => { if (r.success) this.teams = r.data; });
    }
  }

  toggleSkill(id: number): void {
    const idx = this.form.skillIds.indexOf(id);
    if (idx >= 0) this.form.skillIds.splice(idx, 1);
    else this.form.skillIds.push(id);
  }

  hasSkill(id: number): boolean { return this.form.skillIds.includes(id); }

  nextStep(): void {
    if (this.step === 1) {
      if (!this.form.email || !this.form.firstName || !this.form.lastName) {
        this.error = 'Please fill all required fields'; return;
      }
      if (this.form.password !== this.form.confirmPassword) {
        this.error = 'Passwords do not match'; return;
      }
      if (this.form.password.length < 6) {
        this.error = 'Password must be at least 6 characters'; return;
      }
    }
    this.error = '';
    this.step++;
  }

  register(): void {
    this.loading = true; this.error = '';
    const payload = { ...this.form };
    delete payload.confirmPassword;
    this.auth.register(payload).subscribe({
      next: (res) => {
        this.loading = false;
        if (res.success) this.router.navigate(['/dashboard']);
        else this.error = res.message;
      },
      error: (err) => { this.loading = false; this.error = err.error?.message || 'Registration failed'; }
    });
  }

  get roleLabel(): string {
    const map: any = { PROJECT_MANAGER: 'Project Manager', DEPARTMENT_HEAD: 'Department Head', TEAM_LEAD: 'Team Lead', EMPLOYEE: 'Employee' };
    return map[this.form.role] || this.form.role;
  }

  get skillCategories(): string[] {
    return [...new Set(this.skills.map(s => s.category || 'Other'))];
  }

  getSkillsByCategory(cat: string): Skill[] {
    return this.skills.filter(s => (s.category || 'Other') === cat);
  }
}
<div style="min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--bg);padding:20px">
  <div style="width:100%;max-width:480px">
    <div style="text-align:center;margin-bottom:28px">
      <div style="display:inline-flex;align-items:center;justify-content:center;width:44px;height:44px;background:var(--accent);border-radius:12px;font-size:20px;color:white;font-weight:800;margin-bottom:12px">T</div>
      <div style="font-size:20px;font-weight:800;color:var(--text-primary)">Create Account</div>
    </div>

    <!-- Steps indicator -->
    <div style="display:flex;align-items:center;gap:6px;margin-bottom:24px;padding:0 4px">
      <div *ngFor="let s of [1,2,3]; let i=index" style="display:flex;align-items:center;flex:1;gap:6px">
        <div style="width:24px;height:24px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0"
          [style.background]="step > s ? 'var(--success)' : step === s ? 'var(--accent)' : 'var(--border)'"
          [style.color]="step >= s ? 'white' : 'var(--text-muted)'">{{ s }}</div>
        <div style="flex:1;height:2px;background:var(--border)" *ngIf="i < 2"
          [style.background]="step > s ? 'var(--success)' : 'var(--border)'"></div>
      </div>
    </div>

    <div class="card">
      <div class="card-body">
        <div *ngIf="error" style="background:var(--danger-subtle);border:1px solid rgba(239,68,68,0.2);border-radius:var(--radius-sm);padding:10px 14px;margin-bottom:16px;font-size:13px;color:var(--danger)">{{ error }}</div>

        <!-- Step 1: Basic Info -->
        <div *ngIf="step === 1" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:16px">Basic Information</div>
          <div class="two-col">
            <div class="form-group">
              <label class="form-label">First Name *</label>
              <input class="form-control" [(ngModel)]="form.firstName" placeholder="John">
            </div>
            <div class="form-group">
              <label class="form-label">Last Name *</label>
              <input class="form-control" [(ngModel)]="form.lastName" placeholder="Doe">
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Email *</label>
            <input type="email" class="form-control" [(ngModel)]="form.email" placeholder="you@company.com">
          </div>
          <div class="form-group">
            <label class="form-label">Password *</label>
            <input type="password" class="form-control" [(ngModel)]="form.password" placeholder="Minimum 6 characters">
          </div>
          <div class="form-group">
            <label class="form-label">Confirm Password *</label>
            <input type="password" class="form-control" [(ngModel)]="form.confirmPassword" placeholder="Repeat password">
          </div>
          <button class="btn btn-primary w-full" style="justify-content:center;margin-top:4px" (click)="nextStep()">Continue →</button>
        </div>

        <!-- Step 2: Role & Org -->
        <div *ngIf="step === 2" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:16px">Role & Organization</div>
          <div class="form-group">
            <label class="form-label">Role *</label>
            <select class="form-control" [(ngModel)]="form.role">
              <option value="EMPLOYEE">Employee</option>
              <option value="TEAM_LEAD">Team Lead</option>
              <option value="DEPARTMENT_HEAD">Department Head</option>
              <option value="PROJECT_MANAGER">Project Manager</option>
            </select>
          </div>
          <div class="form-group">
            <label class="form-label">Department</label>
            <select class="form-control" [(ngModel)]="form.departmentId" (ngModelChange)="onDeptChange()">
              <option [ngValue]="null">Select department...</option>
              <option *ngFor="let d of departments" [ngValue]="d.id">{{ d.name }}</option>
            </select>
          </div>
          <div class="form-group" *ngIf="form.departmentId && teams.length > 0">
            <label class="form-label">Team</label>
            <select class="form-control" [(ngModel)]="form.teamId">
              <option [ngValue]="null">Select team...</option>
              <option *ngFor="let t of teams" [ngValue]="t.id">{{ t.name }}</option>
            </select>
          </div>
          <div class="two-col">
            <div class="form-group">
              <label class="form-label">Experience (years)</label>
              <input type="number" class="form-control" [(ngModel)]="form.experienceYears" min="0" max="40">
            </div>
            <div class="form-group">
              <label class="form-label">Weekly Capacity (hrs)</label>
              <input type="number" class="form-control" [(ngModel)]="form.maxCapacityHours" min="10" max="80">
            </div>
          </div>
          <div class="form-group">
            <label class="form-label">Bio</label>
            <textarea class="form-control" [(ngModel)]="form.bio" placeholder="Brief introduction..."></textarea>
          </div>
          <div style="display:flex;gap:10px;margin-top:4px">
            <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="step=1">← Back</button>
            <button class="btn btn-primary" style="flex:2;justify-content:center" (click)="nextStep()">Continue →</button>
          </div>
        </div>

        <!-- Step 3: Skills -->
        <div *ngIf="step === 3" class="fade-in">
          <div style="font-size:15px;font-weight:700;margin-bottom:4px">Skills</div>
          <div style="font-size:13px;color:var(--text-muted);margin-bottom:16px">Select your technical skills</div>

          <div *ngFor="let cat of skillCategories" style="margin-bottom:14px">
            <div style="font-size:11px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">{{ cat }}</div>
            <div style="display:flex;flex-wrap:wrap;gap:6px">
              <div *ngFor="let sk of getSkillsByCategory(cat)"
                (click)="toggleSkill(sk.id)"
                [style.background]="hasSkill(sk.id) ? 'var(--accent)' : 'var(--bg-hover)'"
                [style.color]="hasSkill(sk.id) ? 'white' : 'var(--text-secondary)'"
                [style.border]="hasSkill(sk.id) ? '1px solid var(--accent)' : '1px solid var(--border)'"
                style="padding:5px 12px;border-radius:99px;font-size:12px;font-weight:600;cursor:pointer;transition:all 0.15s">
                {{ sk.name }}
              </div>
            </div>
          </div>

          <div *ngIf="error" style="background:var(--danger-subtle);border:1px solid rgba(239,68,68,0.2);border-radius:var(--radius-sm);padding:10px 14px;margin-bottom:12px;font-size:13px;color:var(--danger)">{{ error }}</div>

          <div style="margin-top:8px">
            <div *ngIf="form.role === 'EMPLOYEE'" style="background:var(--warning-subtle);border:1px solid rgba(245,158,11,0.2);border-radius:var(--radius-sm);padding:10px 12px;font-size:12px;color:var(--warning);margin-bottom:12px">
              ⚠ Employee accounts require <strong>Project Manager approval</strong> before tasks can be assigned.
            </div>
            <div style="display:flex;gap:10px">
              <button class="btn btn-secondary" style="flex:1;justify-content:center" (click)="step=2">← Back</button>
              <button class="btn btn-primary" style="flex:2;justify-content:center" (click)="register()" [disabled]="loading">
                {{ loading ? 'Creating account...' : 'Create Account' }}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>

    <div style="text-align:center;margin-top:16px;font-size:13px;color:var(--text-muted)">
      Already have an account?
      <a routerLink="/login" style="color:var(--accent);font-weight:600;margin-left:4px">Sign in</a>
    </div>
  </div>
</div>
